Пример GitHubService (самое сердце)


Dart


Копировать


import 'package:github/github.dart';
import 'package:flutter_secure_storage/flutter_secure_storage.dart';

class GitHubService {
  static const _storage = FlutterSecureStorage();
  static const _tokenKey = 'github_pat';

  GitHub? _client;

  Future<GitHub> get client async {
    if (_client != null) return _client!;

    String? token = await _storage.read(key: _tokenKey);
    if (token == null || token.isEmpty) {
      throw Exception('No GitHub token found. Please login first.');
    }

    _client = GitHub(auth: Authentication.withToken(token));
    return _client!;
  }

  // Получить все открытые issues
  Future<List<Issue>> getTodos({
    required String owner,
    required String repo,
    String state = 'open',
  }) async {
    final gh = await client;
    return await gh.issues.listByRepo(
      RepositorySlug(owner, repo),
      state: state,
      perPage: 50,
    ).toList();
  }

  // Создать новую задачу
  Future<Issue> createTodo({
    required String owner,
    required String repo,
    required String title,
    String? body,
    List<String>? labels,
  }) async {
    final gh = await client;
    return await gh.issues.create(
      RepositorySlug(owner, repo),
      IssueRequest(
        title: title,
        body: body,
        labels: labels,
      ),
    );
  }

  // Закрыть задачу (сделать "done")
  Future<void> closeIssue({
    required String owner,
    required String repo,
    required int issueNumber,
  }) async {
    final gh = await client;
    await gh.issues.edit(
      RepositorySlug(owner, repo),
      issueNumber,
      IssueRequest(state: 'closed'),
    );
  }

  // Сохранить токен после ввода пользователем
  Future<void> saveToken(String token) =>
      _storage.write(key: _tokenKey, value: token);
}


