import 'package:json_annotation/json_annotation.dart';
part 'issue.g.dart';  // генерируется build_runner

@JsonSerializable()
class Issue {
  final int number;
  final String title;
  final String? body;
  final String state;  // 'open' или 'closed'
  final DateTime createdAt;

  Issue({required this.number, required this.title, this.body, required this.state, required this.createdAt});

  factory Issue.fromJson(Map<String, dynamic> json) => _$IssueFromJson(json);
  Map<String, dynamic> toJson() => _$IssueToJson(this);
}


