API-сервис (сердце приложения)
Класс для запросов к GitHub API (endpoint: https://api.github.com/repos/{owner}/{repo}/issues). Пример fetching open issues:


Dart


Копировать


import 'dart:convert';
import 'package:http/http.dart' as http;

class GitHubService {
  final String baseUrl = 'https://api.github.com';
  final String token;

  GitHubService(this.token);

  Future<List<Issue>> fetchIssues(String owner, String repo, {String state = 'open'}) async {
    final uri = Uri.parse('$baseUrl/repos/$owner/$repo/issues?state=$state');
    final response = await http.get(uri, headers: {'Authorization': 'Bearer $token'});
    if (response.statusCode == 200) {
      List<dynamic> jsonList = json.decode(response.body);
      return jsonList.map((json) => Issue.fromJson(json)).toList();
    } else {
      throw Exception('Failed to load issues: ${response.statusCode}');
    }
  }

  Future<Issue> createIssue(String owner, String repo, String title, String? body) async {
    final uri = Uri.parse('$baseUrl/repos/$owner/$repo/issues');
    final response = await http.post(uri,
      headers: {'Authorization': 'Bearer $token', 'Content-Type': 'application/json'},
      body: json.encode({'title': title, 'body': body}),
    );
    if (response.statusCode == 201) {
      return Issue.fromJson(json.decode(response.body));
    } else {
      throw Exception('Failed to create issue');
    }
  }

  Future<void> updateIssue(String owner, String repo, int number, {String? title, String? body, String? state}) async {
    final uri = Uri.parse('$baseUrl/repos/$owner/$repo/issues/$number');
    final bodyMap = {};
    if (title != null) bodyMap['title'] = title;
    if (body != null) bodyMap['body'] = body;
    if (state != null) bodyMap['state'] = state;  // 'open' или 'closed'
    final response = await http.patch(uri,
      headers: {'Authorization': 'Bearer $token', 'Content-Type': 'application/json'},
      body: json.encode(bodyMap),
    );
    if (response.statusCode != 200) {
      throw Exception('Failed to update issue');
    }
  }
}


